hooks.command:
jq -r '.tool_input.file_path' | { read -r f; if [[ "$f" == *.sh ]]; then out=""; if ! o=$(bash -n "$f" 2>&1); then out+="[bash -n]
${o}
"; fi; if ! o=$(shellcheck "$f" 2>&1); then out+="[shellcheck]
${o}
"; fi; if ! o=$(shfmt -d "$f" 2>&1); then out+="[shfmt]
${o}
"; fi; if [[ -n "$out" ]]; then jq -n --arg f "$f" --arg o "$out" '{"hookSpecificOutput":{"hookEventName":"PostToolUse","additionalContext":("shell script issues in "+$f+":
"+$o)}}'; fi; fi; } 2>/dev/null || true
